mapper.select:
SELECT a.id, a.asset_no, a.asset_name, a.category_id, ac.category_name, a.department_id, d.dept_name, a.user_id, u.real_name AS user_real_name, a.purchase_date, a.location, a.status, a.create_time FROM asset a LEFT JOIN asset_category ac ON a.category_id = ac.id AND ac.is_deleted = 0 LEFT JOIN department d ON a.department_id = d.id AND d.is_deleted = 0 LEFT JOIN sys_user u ON a.user_id = u.id AND u.is_deleted = 0
AND a.is_deleted = 0
AND a.asset_no LIKE CONCAT('%', #{assetNo}, '%')
AND a.asset_name LIKE CONCAT('%', #{assetName}, '%')
AND a.category_id = #{categoryId}
AND a.department_id = #{departmentId}
AND a.status = #{status}
ORDER BY a.create_time DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM asset a


    AND a.is_deleted = 0


        AND a.asset_no LIKE CONCAT('%', #{assetNo}, '%')



        AND a.asset_name LIKE CONCAT('%', #{assetName}, '%')



        AND a.category_id = #{categoryId}



        AND a.department_id = #{departmentId}



        AND a.status = #{status}
